{
    // Initialize game with player name (called from JavaScript on game start)
    void Load(const char* name)
    {
        if (name)
        {
            strcpy(player_name,name);  // Store UTF-8 player name
            ConvertToCP437(player_name_cp437,player_name);  // Convert to CP437 encoding
        }

        Main();  // Run main initialization
    }

