"""Playwright test: load game, check console, press backtick for weather."""
import sys
import time
from playwright.sync_api import sync_playwright

def main():
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page()

        console_msgs = []
        errors = []

        page.on("console", lambda msg: console_msgs.append(f"[{msg.type}] {msg.text}"))
        page.on("pageerror", lambda err: errors.append(str(err)))

        print("Loading game at http://localhost:8889/index.html ...")
        try:
            page.goto("http://localhost:8889/index.html", timeout=60000, wait_until="domcontentloaded")
        except Exception as e:
            print(f"ERROR loading page: {e}")
            browser.close()
            return 1

        print(f"Page loaded. Title: {page.title()}")

        # Wait for WASM to load (look for "ALL PASSED" in console or wait)
        print("Waiting for WASM initialization (up to 30s)...")
        for i in range(30):
            time.sleep(1)
            found = [m for m in console_msgs if "ALL PASSED" in m or "PASSED" in m]
            if found:
                print(f"  Init detected at {i+1}s: {found[0]}")
                break
            # Check for fatal errors
            fatal = [m for m in console_msgs if "error" in m.lower() or "Error" in m]
            if fatal:
                print(f"  Errors at {i+1}s:")
                for f in fatal[:5]:
                    print(f"    {f}")
        else:
            print("  Timeout waiting for init")

        # Print all console messages so far
        print(f"\n--- Console messages ({len(console_msgs)}) ---")
        for m in console_msgs:
            print(f"  {m}")

        if errors:
            print(f"\n--- Page errors ({len(errors)}) ---")
            for e in errors:
                print(f"  {e}")

        # Check if Keyb function exists
        keyb_exists = page.evaluate("typeof Keyb")
        print(f"\nKeyb function: {keyb_exists}")

        ak_exists = page.evaluate("typeof ak")
        print(f"ak object: {ak_exists}")

        module_exists = page.evaluate("typeof Module")
        print(f"Module object: {module_exists}")

        # Try pressing backtick
        print("\n--- Pressing backtick key ---")
        console_before = len(console_msgs)
        page.keyboard.press("Backquote")
        time.sleep(1)

        new_msgs = console_msgs[console_before:]
        if new_msgs:
            print(f"New console output after backtick:")
            for m in new_msgs:
                print(f"  {m}")
        else:
            print("No new console output after backtick")

        # Try pressing F3
        print("\n--- Pressing F3 key ---")
        console_before = len(console_msgs)
        page.keyboard.press("F3")
        time.sleep(1)

        new_msgs = console_msgs[console_before:]
        if new_msgs:
            print(f"New console output after F3:")
            for m in new_msgs:
                print(f"  {m}")
        else:
            print("No new console output after F3")

        # Try pressing 'f' for fly toggle
        print("\n--- Pressing 'f' key ---")
        console_before = len(console_msgs)
        page.keyboard.press("f")
        time.sleep(1)

        new_msgs = console_msgs[console_before:]
        if new_msgs:
            print(f"New console output after 'f':")
            for m in new_msgs:
                print(f"  {m}")
        else:
            print("No new console output after 'f'")

        # Check weather state via evaluate
        print("\n--- Direct JS checks ---")
        try:
            result = page.evaluate("""
                (function() {
                    var info = {};
                    info.keyb_type = typeof Keyb;
                    info.ak_type = typeof ak;
                    info.module_type = typeof Module;
                    if (typeof Module !== 'undefined' && Module._akAPI_Call) {
                        info.akAPI_Call = 'available';
                    }
                    if (typeof Module !== 'undefined' && Module.HEAP32) {
