"""Boot test: bypass WebSocket by calling Load() directly."""
import sys, time
from playwright.sync_api import sync_playwright

def main():
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True, args=["--disable-web-security"])
        context = browser.new_context(bypass_csp=True, service_workers="block")
        page = context.new_page()
        msgs = []
        page.on("console", lambda m: msgs.append(f"[{m.type}] {m.text}"))
        page.on("pageerror", lambda err: msgs.append(f"[PAGE_ERROR] {err}"))

        ts = int(time.time())
        page.goto(f"http://localhost:8889/index.html?nocache={ts}", timeout=60000, wait_until="load")
        time.sleep(1)
        page.click("#play-btn")
        print("Clicked Play...")

        # Wait for WASM to be ready (ALL PASSED)
        for i in range(15):
            time.sleep(1)
            if any("ALL PASSED" in m for m in msgs):
                print(f"  WASM ready at {i+1}s")
                break

        # Force solo mode: call Load() directly + start render loop
        print("  Forcing solo mode via JS...")
        page.evaluate("""
            // Kill any pending WebSocket
            if (typeof ak_connection !== 'undefined' && ak_connection) {
                try { ak_connection.close(); } catch(e) {}
            }
            // Call Load directly via Module._Load
            var loadFn = Module.cwrap('Load', null, ['string']);
            loadFn('player');
            // Start render loop if not already running
            var resizeFn = Module.cwrap('Size', null, ['number','number','number','number']);
            resizeFn(window.innerWidth, window.innerHeight, window.innerWidth, window.innerHeight);
        """)
        time.sleep(2)

        print(f"\n--- Console ({len(msgs)} msgs) ---")
        for m in msgs:
            print(f"  {m}")

        has_all_ok = any("all ok" in m for m in msgs)
        has_main = any("[MAIN]" in m for m in msgs)
        print(f"\n  all ok: {has_all_ok}")
        print(f"  [MAIN] logs: {has_main}")

        browser.close()
        return 0

if __name__ == "__main__":
    sys.exit(main())

