// Send network packet to JavaScript multiplayer backend.
// WHY PLATFORM-SPECIFIC: Web uses WebSocket API (JavaScript only), native uses sockets API.
// WHY EM_ASM_INT: WebSocket send happens in JavaScript - C++ bridges via inline JS, returns status.
// Returns true if send succeeded, false if packet too large or send failed.
bool Server::Send(const uint8_t* data, int size)
{
    GameServer* gs = (GameServer*)server;
    if (size > 256)  // Enforce packet size limit
        return false;
    gs->send_buf[0] = size;  // Store packet length in first byte
    memcpy(gs->send_buf+1, data, size);  // Copy packet data
