// Automated multiplayer E2E test for Phase 21
// Opens two browser tabs, connects to relay, clicks New Game, checks loading completes.
//
// Usage: npx playwright test scripts/test_multiplayer_e2e.js
// Or:    node scripts/test_multiplayer_e2e.js

const { chromium } = require('playwright');

const BASE_URL = 'http://localhost:8000';
const TIMEOUT_CONNECT = 15000;  // 15s for WS connect
const TIMEOUT_LOAD = 60000;     // 60s for world loading
const TIMEOUT_ENTER = 10000;    // 10s to enter world after loading

async function waitForConsoleMessage(page, pattern, timeout) {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => reject(new Error(`Timeout waiting for console: ${pattern}`)), timeout);
    const handler = (msg) => {
      const text = msg.text();
      if (text.match(pattern)) {
        clearTimeout(timer);
        page.removeListener('console', handler);
        resolve(text);
      }
    };
    page.on('console', handler);
  });
}

async function collectConsoleLogs(page, duration) {
  const logs = [];
  const handler = (msg) => logs.push({ type: msg.type(), text: msg.text() });
  page.on('console', handler);
  await new Promise(r => setTimeout(r, duration));
  page.removeListener('console', handler);
  return logs;
}

async function runTest() {
  console.log('=== Phase 21 Multiplayer E2E Test ===\n');

  const browser = await chromium.launch({
    headless: false,  // Need visible browser for WebGL
    args: [
      '--disable-web-security',
      '--autoplay-policy=no-user-gesture-required',
      '--use-gl=angle',  // WebGL support
    ]
  });

  const context = await browser.newContext({
    viewport: { width: 1200, height: 800 },
    bypassCSP: true,
  });

  // Collect ALL console messages for both tabs
  const tab1Logs = [];
  const tab2Logs = [];

  try {
    // --- Tab 1 ---
    console.log('[Tab1] Opening page...');
    const page1 = await context.newPage();
    page1.on('console', msg => {
      const text = msg.text();
      tab1Logs.push(text);
      if (text.includes('[LOAD]') || text.includes('[GAME_STATE]') || text.includes('[MM]') ||
          text.includes('ws ') || text.includes('RENDER CRASHED') || text.includes('Join('))
        console.log(`  [Tab1 console] ${text}`);
    });
    page1.on('pageerror', err => console.error(`  [Tab1 ERROR] ${err.message}`));

    await page1.goto(BASE_URL, { waitUntil: 'domcontentloaded' });

    // Fill in player name and click PLAY
    console.log('[Tab1] Filling login form...');
    await page1.waitForSelector('#player-name', { timeout: 30000 });
    await page1.fill('#player-name', 'Tab1');
    await page1.click('#play-btn:not([disabled])', { timeout: 30000 }).catch(async () => {
      // Button might be disabled initially, wait for it
      console.log('[Tab1] Waiting for PLAY button to enable...');
      await page1.waitForFunction(() => !document.getElementById('play-btn').disabled, { timeout: 30000 });
      await page1.click('#play-btn');
    });

    // Wait for WebSocket connection
    console.log('[Tab1] Waiting for WS connection...');
    const ws1 = await waitForConsoleMessage(page1, /ws ready|ws url:.*wss:/, TIMEOUT_CONNECT);
    console.log(`[Tab1] Connected: ${ws1}`);

    // Wait for main menu to be ready (sprites loaded)
    console.log('[Tab1] Waiting for main menu...');
    await waitForConsoleMessage(page1, /MAIN MENU OK|all ok/, TIMEOUT_CONNECT);
    console.log('[Tab1] Main menu ready');

    // Small delay to let rendering stabilize
    await new Promise(r => setTimeout(r, 2000));

    // --- Tab 2 ---
    console.log('\n[Tab2] Opening page...');
    const page2 = await context.newPage();
    page2.on('console', msg => {
      const text = msg.text();
      tab2Logs.push(text);
      if (text.includes('[LOAD]') || text.includes('[GAME_STATE]') || text.includes('[MM]') ||
          text.includes('ws ') || text.includes('RENDER CRASHED') || text.includes('Join('))
        console.log(`  [Tab2 console] ${text}`);
    });
    page2.on('pageerror', err => console.error(`  [Tab2 ERROR] ${err.message}`));

    await page2.goto(BASE_URL, { waitUntil: 'domcontentloaded' });

    console.log('[Tab2] Filling login form...');
    await page2.waitForSelector('#player-name', { timeout: 30000 });
    await page2.fill('#player-name', 'Tab2');
    await page2.click('#play-btn:not([disabled])', { timeout: 30000 }).catch(async () => {
      console.log('[Tab2] Waiting for PLAY button to enable...');
      await page2.waitForFunction(() => !document.getElementById('play-btn').disabled, { timeout: 30000 });
      await page2.click('#play-btn');
    });

    console.log('[Tab2] Waiting for WS connection...');
    const ws2 = await waitForConsoleMessage(page2, /ws ready|ws url:.*wss:/, TIMEOUT_CONNECT);
    console.log(`[Tab2] Connected: ${ws2}`);

    await waitForConsoleMessage(page2, /MAIN MENU OK|all ok/, TIMEOUT_CONNECT);
    console.log('[Tab2] Main menu ready');

    await new Promise(r => setTimeout(r, 2000));

    // --- Click New Game on both tabs ---
    // The C++ main menu is rendered on canvas. "NEW GAME" is navigable via keyboard.
    // Menu structure: first item could be CONTINUE (if game was loaded before) or NEW GAME.
    // We'll use keyboard: press Down to highlight NEW GAME, then Enter.

    console.log('\n[Tab1] Clicking New Game via keyboard...');
    const canvas1 = await page1.$('canvas');
    await canvas1.focus();
    // Press Enter to open menu if needed, then navigate to NEW GAME
    await page1.keyboard.press('ArrowDown');
    await new Promise(r => setTimeout(r, 200));
    await page1.keyboard.press('Enter');
    await new Promise(r => setTimeout(r, 200));
    // If we're in a submenu, the first item on root should be NEW GAME (when game_loading==0)
    // Try pressing Enter directly — if no menu is open, ArrowDown+Enter opens root and picks first
    await page1.keyboard.press('Enter');

    console.log('[Tab1] Waiting for loading to start...');
    const load1Start = await waitForConsoleMessage(page1, /LOADING_LEVEL|game_loading=1/, TIMEOUT_ENTER)
      .catch(() => null);

    if (!load1Start) {
      // Menu navigation might not have worked. Try mouse click on canvas center-ish area
      console.log('[Tab1] Keyboard nav failed, trying mouse click on NEW GAME area...');
      const box1 = await canvas1.boundingBox();
      // NEW GAME is typically in the lower-left area of the menu
      // Try clicking at roughly the right position
      await page1.mouse.click(box1.x + box1.width * 0.25, box1.y + box1.height * 0.6);
      await new Promise(r => setTimeout(r, 500));
      await page1.mouse.click(box1.x + box1.width * 0.25, box1.y + box1.height * 0.6);
    }

    // Wait for loading to complete (ENTERED_WORLD)
    console.log('[Tab1] Waiting for world load...');
    const world1 = await waitForConsoleMessage(page1, /ENTERED_WORLD/, TIMEOUT_LOAD)
      .catch(e => { console.error(`[Tab1] FAILED: ${e.message}`); return null; });

    if (world1) {
      console.log('[Tab1] SUCCESS: Entered world!');
    } else {
      // Check what progress we reached
      const lastProgress = tab1Logs.filter(l => l.includes('[MM]')).pop();
      const lastLoad = tab1Logs.filter(l => l.includes('[LOAD]')).pop();
      console.log(`[Tab1] Last progress: ${lastProgress || 'none'}`);
      console.log(`[Tab1] Last load: ${lastLoad || 'none'}`);
      const crashed = tab1Logs.find(l => l.includes('RENDER CRASHED'));
      if (crashed) console.error(`[Tab1] CRASH: ${crashed}`);
    }

    // Now Tab 2
    console.log('\n[Tab2] Clicking New Game via keyboard...');
    const canvas2 = await page2.$('canvas');
    if (canvas2) {
      await canvas2.focus();
      await page2.keyboard.press('ArrowDown');
      await new Promise(r => setTimeout(r, 200));
      await page2.keyboard.press('Enter');
      await new Promise(r => setTimeout(r, 200));
      await page2.keyboard.press('Enter');
    }

    console.log('[Tab2] Waiting for loading to start...');
    const load2Start = await waitForConsoleMessage(page2, /LOADING_LEVEL|game_loading=1/, TIMEOUT_ENTER)
      .catch(() => null);

    if (!load2Start && canvas2) {
      console.log('[Tab2] Keyboard nav failed, trying mouse click...');
      const box2 = await canvas2.boundingBox();
      await page2.mouse.click(box2.x + box2.width * 0.25, box2.y + box2.height * 0.6);
      await new Promise(r => setTimeout(r, 500));
      await page2.mouse.click(box2.x + box2.width * 0.25, box2.y + box2.height * 0.6);
    }

    console.log('[Tab2] Waiting for world load...');
    const world2 = await waitForConsoleMessage(page2, /ENTERED_WORLD/, TIMEOUT_LOAD)
      .catch(e => { console.error(`[Tab2] FAILED: ${e.message}`); return null; });

    if (world2) {
      console.log('[Tab2] SUCCESS: Entered world!');
    } else {
      const lastProgress = tab2Logs.filter(l => l.includes('[MM]')).pop();
      const lastLoad = tab2Logs.filter(l => l.includes('[LOAD]')).pop();
      console.log(`[Tab2] Last progress: ${lastProgress || 'none'}`);
      console.log(`[Tab2] Last load: ${lastLoad || 'none'}`);
    }

    // --- Verdict ---
    console.log('\n=== VERDICT ===');
    const tab1OK = !!world1;
    const tab2OK = !!world2;

    if (tab1OK && tab2OK) {
      console.log('PASS: Both tabs loaded world successfully');
    } else if (tab1OK || tab2OK) {
      console.log('PARTIAL: Only one tab loaded (' + (tab1OK ? 'Tab1' : 'Tab2') + ')');
    } else {
      console.log('FAIL: Neither tab loaded world');
    }

    // Check if both tabs see each other (BRC_JOIN for the other player)
    const tab1SawTab2 = tab1Logs.some(l => l.includes('Tab2 joined') || l.includes('joined'));
    const tab2SawTab1 = tab2Logs.some(l => l.includes('Tab1 joined') || l.includes('joined'));
    console.log(`Tab1 saw other player join: ${tab1SawTab2}`);
    console.log(`Tab2 saw other player join: ${tab2SawTab1}`);

    // Dump key logs for debugging
    console.log('\n--- Tab1 Key Logs ---');
    tab1Logs.filter(l =>
      l.includes('ws ') || l.includes('[LOAD]') || l.includes('[MM]') ||
      l.includes('[GAME_STATE]') || l.includes('CRASH') || l.includes('Join(') ||
      l.includes('solo') || l.includes('error')
    ).forEach(l => console.log(`  ${l}`));

    console.log('\n--- Tab2 Key Logs ---');
    tab2Logs.filter(l =>
      l.includes('ws ') || l.includes('[LOAD]') || l.includes('[MM]') ||
      l.includes('[GAME_STATE]') || l.includes('CRASH') || l.includes('Join(') ||
      l.includes('solo') || l.includes('error')
    ).forEach(l => console.log(`  ${l}`));

    // Keep browser open briefly to inspect visually
    await new Promise(r => setTimeout(r, 5000));

